window.DAILY_NEWS_ISSUES["2026-06-26"] = {"id": "tech-2026-06-26", "section_slug": "tech", "publication_name": "我的日报·科技", "issue_date": "2026-06-26", "volume": 1, "number": 4, "date_cn": "2026 年 6 月 26 日 · 周五", "output_path": "issues/2026-06-26.html", "headlines": [{"source_item_ids": ["cdd77d01d10b9acd"], "kicker": "芯片 · 发布", "title_zh": "OpenAI联手博通发布首款定制AI芯片Jalapeño，专为大模型推理设计", "summary_zh": "OpenAI与芯片供应商博通联合发布名为Jalapeño的定制芯片，这是一款专为数据中心大语言模型（LLM）推理设计的专用集成电路（ASIC），标志OpenAI正式入局AI芯片。", "read_body_zh": ["据Ars Technica报道，ChatGPT与Codex背后的公司OpenAI，与老牌芯片供应商博通联合发布了名为Jalapeño的新芯片，专为数据中心内大语言模型推理而设计。两家公司计划将该芯片部署于大型数据中心，并称这只是一个长期项目的第一代产品，未来将持续迭代。", "博通表示，这款ASIC是基于与OpenAI研究人员的深入交流、从零开始为LLM推理设计的，其开发参考了OpenAI对未来模型与产品的路线图。芯片从设计到生产耗时9个月。", "OpenAI称，早期测试显示Jalapeño的每瓦性能将大幅优于当前最先进水平，但同时指出性能测量尚未完成，更详细的技术报告将在未来数月发布。据界面新闻报道，该平台计划于2026年底开始部署。"], "pullquote": {"text": "早期测试显示，Jalapeño的每瓦性能将大幅优于当前最先进水平。", "cite": "OpenAI"}, "ai_impact": "这是头部模型公司向自研推理芯片纵深整合的标志性一步，意在缓解算力供应紧张并降低长期推理成本，可能削弱对单一GPU供应商的依赖，对英伟达主导的AI算力格局构成中长期变量。但首代芯片性能仍待完整技术报告验证，实际部署效果存在不确定性。", "sources": [{"name": "Ars Technica", "url": "https://arstechnica.com/gadgets/2026/06/openai-and-broadcom-announce-chip-designed-for-llm-inference-at-scale"}], "relevance_score": 95, "importance_score": 91}, {"source_item_ids": ["b0d1ef31d74a4879"], "kicker": "大模型 · 监管", "title_zh": "应特朗普政府要求，OpenAI推迟GPT-5.6并改为受限预览发布", "summary_zh": "据The Information报道，OpenAI将把下一代旗舰模型GPT-5.6改为限量预览发布，先只向少数企业客户开放，且预览期内客户的访问权限将由特朗普政府逐案审批。", "read_body_zh": ["The Verge援引The Information报道称，出于对潜在安全问题的担忧，特朗普政府要求OpenAI分阶段发布其下一代重磅模型GPT-5.6。OpenAI首席执行官山姆·奥特曼在周三公司问答中告诉员工，公司将以受限预览形式发布GPT-5.6，仅向一小部分企业客户开放，以配合联邦政府的要求。", "报道称，在预览期内，特朗普政府本身将逐案批准客户的访问权限。", "The Verge指出，相比之下这一安排比政府此前给OpenAI竞争对手Anthropic的条件更宽松。本月早些时候，Anthropic收到要求暂停其Mythos 5和Fable 5模型访问的最后通牒，政府发布的出口管制指令禁止“外国国民”访问该技术，包括Anthropic自身非美国籍的员工。"], "pullquote": null, "ai_impact": "美国政府以逐案审批方式介入前沿模型发布，显示AI监管正从“速度优先”转向更强的安全管控，并在不同公司间出现不均衡待遇。这会增加大模型发布的不确定性，影响企业客户获取最新能力的节奏，也可能重塑头部AI公司与政府的博弈关系。", "sources": [{"name": "The Verge", "url": "https://www.theverge.com/ai-artificial-intelligence/957372/openai-will-delay-gpt-5-6-after-trump-administration-request"}], "relevance_score": 92, "importance_score": 89}, {"source_item_ids": ["21f3e0a285e804cd"], "kicker": "苹果 · 供应链", "title_zh": "存储芯片紧缺蔓延至苹果，Mac、iPad等多条产品线集体涨价", "summary_zh": "苹果罕见地对Mac、iPad、HomePod乃至Vision Pro等几乎全线产品上调价格，部分机型涨幅达数百美元，原因是AI数据中心扩张引发的内存与存储芯片短缺推高了零部件成本。", "read_body_zh": ["据The Verge报道，苹果当天上调了几乎所有产品线的价格，涉及Mac、iPad、HomePod甚至Vision Pro，许多机型价格上涨数百美元，例如MacBook Neo的起步价从599美元涨至699美元。报道称iPhone暂时未受影响。", "文章指出，苹果通常不会调整在售机型的价格，凭借丰厚利润率和巨大采购量，它本可比其他厂商更能消化供应链价格波动；当连苹果都涨价时，说明存储危机已严重到改写消费电子定价规则。", "据36氪援引澎湃新闻报道，苹果在声明中称AI数据中心迅猛扩张导致存储需求激增，零部件价格以前所未见的幅度和速度上涨，公司此前一直在内部消化成本压力，但现已不得不上调多款产品售价。此前游戏主机、笔记本、手机已相继因内存短缺涨价。"], "pullquote": {"text": "AI数据中心的迅猛扩张导致存储需求激增，我们从未见过零部件价格以如此幅度和速度上涨。", "cite": "苹果公司声明"}, "ai_impact": "苹果作为供应链议价能力最强的厂商被迫全线涨价，是AI算力需求外溢冲击消费电子的强烈信号，表明存储紧缺已从产业内部传导至终端消费者。这预示未来数年消费电子成本压力将持续，并放大AI基础设施投资对整体科技产业链价格结构的重塑作用。", "sources": [{"name": "The Verge", "url": "https://www.theverge.com/tech/956950/ram-crisis-apple-price-increase"}], "relevance_score": 86, "importance_score": 84}, {"source_item_ids": ["df1a4dbc9a73eb71"], "kicker": "半导体 · 地缘", "title_zh": "欧洲就对华芯片设备限制向华盛顿施压，ASML成焦点", "summary_zh": "荷兰贸易大臣赴华盛顿会见美国商务部长和国会议员，公开反对MATCH法案。该法案将禁止中国芯片制造商获取西方半导体设备，对欧洲市值最高公司、全球唯一先进光刻机制造商ASML打击尤重。", "read_body_zh": ["据TechCrunch报道，荷兰贸易大臣Sjoerd Sjoerdsma本周访问华盛顿，会见美国商务部长卢特尼克及国会议员，以反对MATCH法案。该法案将禁止中国芯片制造商获取西方半导体设备，对总部位于荷兰的ASML打击尤为严重。ASML是欧洲市值最高的公司，也是全球唯一能制造用于尖端AI芯片的高端光刻机的厂商。", "Sjoerdsma在会后对彭博社表示，自己专程前来向国会广泛阐明关切“是很罕见的”，并称“荷兰的利害关系可能非常高”。中国市场占ASML系统净销售额的19%。", "MATCH法案将比现有管制走得更远，在长期禁止最先进的极紫外（EUV）设备进入中国之外，进一步把ASML的深紫外浸没式光刻机也纳入限制。ASML首席执行官此前曾对TechCrunch表示，中国目前能买到的只是约十年前首次出货的上一代深紫外设备。该法案于4月提出，尚未经过参众两院全院表决。"], "pullquote": null, "ai_impact": "荷兰罕见高规格游说反映美国出口管制正引发盟友内部分歧，半导体设备已成大国科技博弈的核心筹码。若MATCH法案通过，将进一步收紧全球先进制程供应链，影响AI芯片制造布局，并可能促使中国加速设备国产化，重塑全球半导体产业格局。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/24/europe-is-pushing-back-on-washingtons-chip-war"}], "relevance_score": 80, "importance_score": 87}, {"source_item_ids": ["36efc122f37f6312"], "kicker": "自动驾驶 · 政策", "title_zh": "美国交通部拟取消自动驾驶车辆刹车踏板要求，特斯拉受益", "summary_zh": "特朗普政府的交通部提议修改联邦车辆法规，允许“专为自动驾驶系统设计”的车辆不再配备刹车踏板，将为特斯拉、Zoox等开发全自动无人车的公司扫除一大监管障碍。", "read_body_zh": ["据TechCrunch报道，美国交通部（DOT）提出新规，允许厂商在“专为自动驾驶系统驾驶的车辆”中省去刹车踏板。该提案若获采纳，将为特斯拉和亚马逊旗下Zoox等正在开发无方向盘、无踏板全自动车辆的公司移除重大监管障碍。公众将有30天时间对提案发表意见。", "目前任何缺少联邦机动车安全标准（FMVSS）所要求部件的自动驾驶车辆，都须向联邦政府申请豁免，且即便获批，上路数量也受限制。NHTSA表示，取消刹车踏板等部件要求理论上可让企业更快地把自动驾驶车辆投入道路。", "特斯拉过去几年一直在开发名为Cybercab的双座无方向盘、无踏板车型，但从未申请FMVSS豁免，CEO马斯克多次表示一旦获得监管批准就会全国部署。同时特斯拉过去一年在德州奥斯汀运营小规模Robotaxi服务，并已逐步撤下安全员，承认在事故后或避障时使用远程操作员低速移动车辆。"], "pullquote": null, "ai_impact": "联邦层面松绑无方向盘、无踏板车辆的硬性要求，将显著降低全自动Robotaxi量产上路的合规门槛，对押注Cybercab的特斯拉构成直接政策利好，也利好Zoox等专用无人车厂商。这可能加快美国Robotaxi商业化节奏，但安全监管框架的重塑及公众意见仍存变数。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/25/trump-admin-proposes-axing-brake-pedal-requirement-for-avs-in-a-boost-for-tesla"}], "relevance_score": 84, "importance_score": 82}], "briefs": [{"source_item_ids": ["e0ce3f863470180e"], "title_zh": "Anthropic的Claude在付费消费者市场持续抢占ChatGPT份额", "summary_zh": "信用卡交易分析公司Indagari数据显示，付费AI消费者越来越多地选择Anthropic的Claude，该细分市场自2026年1月以来增长约75%。教育平台DataCamp称Claude已成站内搜索量最高的词，相关课程需求30天内增长18倍。但ChatGPT在付费用户规模上仍遥遥领先。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/25/anthropics-claude-is-winning-over-paid-consumers-a-market-owned-by-chatgpt"}], "relevance_score": 72, "importance_score": 69}, {"source_item_ids": ["21ecbf20c5912668"], "title_zh": "IBM宣称推出全球首个“亚1纳米”芯片技术", "summary_zh": "IBM发布其称为“全球首个亚1纳米”的芯片技术，采用新型“nanostack”三维堆叠架构，可在指甲盖大小的芯片上集成近1000亿个晶体管，晶体管密度约为其2021年2纳米芯片的两倍，面向AI数据中心。IBM强调该节点编号并不对应实际物理尺寸，而是指可达到的等效性能。据爱范儿报道，相比2纳米节点最高可带来50%性能提升或70%能效提升。", "sources": [{"name": "Ars Technica", "url": "https://arstechnica.com/gadgets/2026/06/ibm-claims-worlds-first-sub-1-nanometer-chip-technology"}], "relevance_score": 76, "importance_score": 78}, {"source_item_ids": ["921f44b00eb2454e"], "title_zh": "亚马逊再投130亿美元扩建印度AI与云基础设施", "summary_zh": "亚马逊宣布将在2030年前追加投资130亿美元，扩大其在印度的AI与云业务，资金将用于扩建AWS在孟买和海得拉巴的数据中心容量。这是亚马逊三年内对印度的第三次重大承诺，使其在印投资承诺总额达480亿美元。微软、谷歌等也已在印度作出大额AI基础设施投资。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/25/amazon-ups-india-bet-with-fresh-13b-ai-infrastructure-investment"}], "relevance_score": 62, "importance_score": 72}, {"source_item_ids": ["d74aff67b2720761"], "title_zh": "Cerebras上市后首份财报引发股价大跌近20%", "summary_zh": "AI芯片公司Cerebras上市后首份财报虽营收超预期（季度营收1.93亿美元、同比增94%，净亏损收窄至1400万美元），但因预计核心业务全年毛利率将从一季度的47%降至38%—41%而吓退投资者，股价当日下跌近20%、逼近IPO发行价。CEO称投资者误读了毛利率指引，部分原因是公司需向大客户回租设备。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/24/cerebras-stock-plunges-after-earnings-as-ceo-says-margin-outlook-was-misunderstood"}], "relevance_score": 78, "importance_score": 66}, {"source_item_ids": ["c4626df098d8777f"], "title_zh": "谷歌AI研究员持续流失，两名Gemini关键贡献者投奔Anthropic", "summary_zh": "据彭博社报道，谷歌资深AI研究员Jonas Adler和Alexander Pritzel将离职加入Anthropic，两人在Gemini模型开发中发挥了关键作用。此前传奇研究员Noam Shazeer已离开谷歌加入OpenAI，DeepMind总监、2024年诺贝尔化学奖得主John Jumper也已转投Anthropic。报道认为随着OpenAI和Anthropic筹备上市，这一人才流失趋势可能延续。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/24/ai-researchers-continue-to-leave-google-for-its-rivals"}], "relevance_score": 78, "importance_score": 70}, {"source_item_ids": ["042bd1af0e357745"], "title_zh": "苹果据称跳过高端M6芯片，转向AI导向的M7系列", "summary_zh": "据彭博社（经Hacker News转载）报道，苹果正对Mac芯片战略做出重大调整，计划最快今年为入门级Mac推出基础版M6处理器，但首次跳过该代的高端版本，转而直接推进面向AI的新一代M7系列处理器。苹果目前在售的是M5系列。", "sources": [{"name": "Bloomberg", "url": "https://www.bloomberg.com/news/articles/2026-06-25/apple-to-skip-high-end-m6-mac-chips-to-launch-m7-pro-m7-max-m7-ultra-instead"}], "relevance_score": 82, "importance_score": 68}, {"source_item_ids": ["72037c5a6ca0d584"], "title_zh": "Notion关停邮件应用Notion Mail，转向用AI代理处理收件箱", "summary_zh": "Notion宣布将于9月22日在网页、桌面和iOS端关闭Notion Mail收件箱，这是其2024年收购Skiff后所剩业务的终结。Notion称多数用户已不再使用邮件客户端，目前超过一半的Notion Mail用户从不打开收件箱、而是依靠AI代理处理邮件，因此公司将“全力押注用代理来运行收件箱”。用户邮件数据将保留在Gmail中。", "sources": [{"name": "Ars Technica", "url": "https://arstechnica.com/gadgets/2026/06/notion-killing-skiff-influenced-email-app-since-most-users-use-ai-agents-instead"}], "relevance_score": 66, "importance_score": 58}, {"source_item_ids": ["18d6bb87b9489702", "ae8fe7a141fb87b1"], "title_zh": "美光受AI存储需求带动业绩爆发，单季营收同比大增", "summary_zh": "美国最大内存芯片厂商美光发布2026财年第三财季财报，营收约414.6亿美元、同比大增约346%，净利润达282.4亿美元，财报后盘后股价一度涨超15%。公司预计第四财季营收约500亿美元。美光还披露16份长期供货协议，按价格下限计算累计价值高达1000亿美元，并称存储供应紧张将持续到2027年之后。受其催化，A股与韩国半导体板块同步走高。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/24/the-memory-chip-crunch-is-paying-off-for-this-u-s-company"}, {"name": "36氪", "url": "https://36kr.com/p/3868523068298499?f=rss"}], "relevance_score": 79, "importance_score": 74}, {"source_item_ids": ["ca3366cc682f4b7f"], "title_zh": "Anthropic指控阿里巴巴发动迄今最大规模Claude克隆攻击", "summary_zh": "据Ars Technica报道，Anthropic在致美国参议员的信中称，与阿里巴巴及其AI实验室阿里千问相关的操作者，在4月22日至6月5日间通过近2.5万个欺诈账户与Claude进行了超过2880万次交互，意在窃取Claude的智能体推理、软件工程等核心能力，并使用混淆技术与代理网络逃避检测。Anthropic称此举发生在特朗普政府就此类“蒸馏攻击”发出警告之后。", "sources": [{"name": "Ars Technica", "url": "https://arstechnica.com/tech-policy/2026/06/anthropic-claims-alibaba-defied-trump-to-attack-claude-and-steal-capabilities"}], "relevance_score": 70, "importance_score": 67}, {"source_item_ids": ["1bc510e8f318bf86"], "title_zh": "观点：当前大模型的高定价不可持续", "summary_zh": "一篇登上Hacker News的博客文章论证，当前前沿大模型的高昂价格难以为继。作者列举五大原因：模型性能提升趋于平缓、开源权重模型（如GLM-5.2以约1/10成本媲美GPT和Opus）崛起、专用芯片与架构改进降低推理成本、模型间近乎零的切换成本，以及未来数年本地模型的普及。作者预测价格压力终将到来，对消费者有利。", "sources": [{"name": "Hacker News", "url": "https://aditya.patadia.org/p/ai-and-cloud-costs"}], "relevance_score": 64, "importance_score": 60}, {"source_item_ids": ["a9cdddbbe4d01d80"], "title_zh": "前Databricks AI负责人推出新架构，称可将AI能耗降至千分之一", "summary_zh": "由前Databricks AI负责人Naveen Rao领导的Unconventional AI发布首个模型Un-0，这是一个图像生成系统，首次展示其基于振荡器的全新计算架构可复现传统AI系统的能力，效果与最先进的扩散模型相当。Rao称该架构最终可将推理能耗降低多达1000倍。目前Un-0运行在对其振荡器芯片的软件模拟之上，公司计划很快发布实际芯片的设计图。该公司员工不足50人。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/25/databricks-former-ai-chief-thinks-he-can-cut-ais-power-bill-by-1000x"}], "relevance_score": 65, "importance_score": 63}, {"source_item_ids": ["925343848b705789"], "title_zh": "Adobe收购图像视频增强工具厂商Topaz Labs", "summary_zh": "Adobe宣布收购成立逾二十年的Topaz Labs，后者提供用于视频和图像增强的AI模型（如视频超分的Astra和图像修饰的Wonder），并曾凭其制作技术获艾美奖。Adobe表示将把Topaz的模型整合进Firefly AI应用及其图像视频编辑套件，同时保留其独立服务。Adobe称看重Topaz在终端设备上运行大型复杂AI模型的专长。交易预计于2026年下半年完成。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/25/adobe-acquires-image-and-video-enhancement-tool-maker-topaz-labs"}], "relevance_score": 61, "importance_score": 62}, {"source_item_ids": ["0e673947506e4800"], "title_zh": "SpaceX计划在美推出星链零售移动服务并自建地面移动网络", "summary_zh": "据财联社报道，马斯克旗下SpaceX计划面向美国消费者推出全新的星链移动服务。公司总裁兼首席运营官肖特韦尔表示正考虑“推出星链零售产品”，并可能在美国建设自己的地面移动网络。实施该计划需向个人客户出售移动合约，将使SpaceX与Verizon、AT&T和T-Mobile等美国主要运营商展开竞争。", "sources": [{"name": "36氪", "url": "https://36kr.com/newsflashes/3869747968136457?f=rss"}], "relevance_score": 58, "importance_score": 64}, {"source_item_ids": ["265f247277777209"], "title_zh": "新数据显示工程岗位在AI冲击下反而最具韧性", "summary_zh": "风投机构SignalFire的报告显示，尽管AI常被列为裁员主因，工程岗位却是2025年最具韧性的职能。大型科技公司整体招聘较2019年下降25%，而工程岗位仅下降11%；在12家“科技巨头”中，工程师占2025年新招人数的55%，高于2019年的46%。Anthropic经济主管和英伟达CEO黄仁勋均表示尚未看到AI对工程岗位的显著替代效应，黄仁勋称用上AI代理后“软件工程师比以往任何时候都忙”。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/24/ai-was-supposed-to-kill-engineering-jobs-but-new-data-suggests-theyre-the-most-resilient"}], "relevance_score": 55, "importance_score": 59}], "discarded": [{"source_item_ids": ["0d9df83373aadbac"], "reason": "聚合早报混合苹果涨价、英伟达股东会、OpenAI芯片、IBM芯片等多件事，单条事件已有更清晰来源入选，避免重复和混合选题。", "relevance_score": 82, "importance_score": 70}, {"source_item_ids": ["792b8576a2d801f9"], "reason": "访谈和观点性内容较强，不是明确突发事件；虽涉及AI泡沫、物理AI和自动驾驶，但优先级低于硬新闻。", "relevance_score": 66, "importance_score": 55}, {"source_item_ids": ["a7289794982945c5"], "reason": "Show HN项目发布偏小众工具和社区自荐，接近小产品营销，不适合作为本期科技日报选题。", "relevance_score": 38, "importance_score": 24}, {"source_item_ids": ["be29c46137231e82"], "reason": "早报聚合稿包含OpenAI芯片、豆包、特斯拉车机等多项内容，核心OpenAI芯片已有独立报道入选，避免重复。", "relevance_score": 62, "importance_score": 48}, {"source_item_ids": ["a724f0bf19a9b0fc"], "reason": "早报聚合稿覆盖苹果涨价、美光、IBM、OpenAI IPO等多件事，相关事件已有更聚焦来源入选。", "relevance_score": 61, "importance_score": 50}, {"source_item_ids": ["4367d6953a7c202d"], "reason": "主要是小公司融资和案例包装，虽提到工业世界模型和半导体落地，但符合避免项中的小公司融资倾向。", "relevance_score": 42, "importance_score": 32}, {"source_item_ids": ["938922fe20198833"], "reason": "网络犯罪打击事件本身有价值，但未命中本期重点关注的AI芯片、大模型、自动驾驶、半导体或指定公司。", "relevance_score": 20, "importance_score": 58}], "merged_sources": [{"source_item_ids": ["18d6bb87b9489702", "ae8fe7a141fb87b1"], "reason": "同一事件：美光受AI带动的存储芯片紧缺和财报超预期"}]};
